import{_ as i,o as a,c as e,a0 as p}from"./chunks/framework.Dx25mwie.js";const E=JSON.parse('{"title":"Go-Spring 实战第 8 课 —— 变量引用与动态刷新：配置值如何复用和更新","description":"","frontmatter":{"head":[]},"headers":[],"relativePath":"docs/8.wechat-series/08-configuration-refresh.md","filePath":"docs/8.wechat-series/08-configuration-refresh.md"}'),n={name:"docs/8.wechat-series/08-configuration-refresh.md"};function h(t,s,l,k,r,o){return a(),e("div",null,[...s[0]||(s[0]=[p('<h1 id="go-spring-实战第-8-课-——-变量引用与动态刷新-配置值如何复用和更新" tabindex="-1">Go-Spring 实战第 8 课 —— 变量引用与动态刷新：配置值如何复用和更新 <a class="header-anchor" href="#go-spring-实战第-8-课-——-变量引用与动态刷新-配置值如何复用和更新" aria-label="Permalink to &quot;Go-Spring 实战第 8 课 —— 变量引用与动态刷新：配置值如何复用和更新&quot;">​</a></h1><p>到这里，Go-Spring 配置系统的主线已经基本走完了。在前面几篇里，我们先用 <code>Properties</code> 和 <code>path</code> 建立了统一的配置模型，然后把配置绑定到了 Go 类型，接着处理了 <code>Duration</code>、<code>Time</code>、<code>Slice</code>、<code>Map</code> 等复杂类型，然后我们又用 <code>expr</code> 标签拦截非法配置，还把 Reader、Provider、环境变量和命令行参数等不同来源接入进来，最后讨论了配置优先级、合并语义和 Profile 机制。</p><p>这一篇是 Go-Spring 配置系列的最后一篇，咱们来讨论两个很重要的收尾问题。第一个问题是配置复用。同一个地址、目录、端口或密码可能会被多个配置项引用，如果每个地方都手写一遍，那后续修改就很容易出现遗漏。第二个问题是运行期更新。对于开关、阈值、超时时间这类轻量参数，我们有时希望在不重启进程的情况下也能够读到新值。</p><p>在 Go-Spring 中，配置复用可以通过变量引用解决，运行期更新可以通过动态刷新解决。</p><h2 id="变量引用" tabindex="-1">变量引用 <a class="header-anchor" href="#变量引用" aria-label="Permalink to &quot;变量引用&quot;">​</a></h2><p>Go-Spring 在解析配置值时，会展开 <code>${...}</code> 格式的表达式，也就是变量引用。展开时，Go-Spring 会找到对应的配置值，并把引用表达式替换成这个值。</p><p>下面的例子覆盖了几种常见的变量引用写法。</p><div class="language-properties vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">properties</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">server.port</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=${port}</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">server.port</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=${port:=8080}</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">app.home</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=${user.home}/myapp</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">app.url</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=http://${app.host}:${app.port}/api</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">redis.password</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=${REDIS_PASSWORD:=}</span></span></code></pre></div><p>在上面的例子中，<code>${port}</code> 表示必须能在配置空间中找到 <code>port</code> 配置项，否则解析就会失败。<code>${port:=8080}</code> 表示找不到 <code>port</code> 时可以使用默认值，解析不会失败。<code>app.home</code> 和 <code>app.url</code> 展示的是普通文本与引用值的混合使用。<code>REDIS_PASSWORD</code> 展示的是对环境变量的引用。</p><p>变量引用最常见的场景，是把一些基础值抽出来复用。比如服务地址、数据目录、外部系统域名这类配置，往往会被多个配置项组合使用。使用变量引用以后，基础值只需要维护一份，其他配置项通过引用来派生即可。</p><p>需要注意的是，变量引用本身不会改变配置来源的优先级，因为变量引用是在所有配置完成合并之后才解析的。也就是说，如果 <code>app.host</code> 同时出现在基础配置、Profile 配置和环境变量里，那么 <code>${app.host}</code> 解析到的仍然是按优先级合并后的最终值，而不是变量引用所在来源或其之前来源中的值。</p><p>另外，Go-Spring 不支持递归引用，也不推荐在配置中设计递归引用。</p><h2 id="动态刷新" tabindex="-1">动态刷新 <a class="header-anchor" href="#动态刷新" aria-label="Permalink to &quot;动态刷新&quot;">​</a></h2><p>Go-Spring 支持在运行期刷新配置的值。我们只需要把需要动态更新的字段声明为 <code>gs.Dync[T]</code> 类型即可，<code>value</code> 标签和 <code>expr</code> 标签的写法、语义都与普通字段相同。<code>gs.Dync[T]</code> 内部使用 <code>atomic.Value</code> 实现并发安全的读写。</p><p>看个例子：</p><div class="language-go vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">go</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">type</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> AppConfig</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> struct</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">	Port </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">int</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> `value:&quot;${server.port}&quot;`</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">	Timeout       </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">gs</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Dync</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">time</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Duration</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">] </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">`value:&quot;${server.timeout:=30s}&quot;`</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">	MaxConns      </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">gs</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Dync</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">int</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]           </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">`value:&quot;${server.max-conns:=100}&quot;`</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">	EnableFeature </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">gs</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Dync</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">bool</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]          </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">`value:&quot;${feature.xxx.enable:=false}&quot;`</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>读取动态配置时，我们需要通过 <code>Value()</code> 方法拿到最新的值：</p><div class="language-go vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">go</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">func</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">a </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">*</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">App</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">handleRequest</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">w</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> http</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ResponseWriter</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">r</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> *</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">http</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Request</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) {</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">	timeout </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> a.Config.Timeout.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Value</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">()</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">	_ </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> timeout</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><h3 id="propertiesrefresher" tabindex="-1">PropertiesRefresher <a class="header-anchor" href="#propertiesrefresher" aria-label="Permalink to &quot;PropertiesRefresher&quot;">​</a></h3><p>动态刷新需要由外部动作触发。Go-Spring 要求在运行时调用 <code>gs.PropertiesRefresher</code> 的 <code>RefreshProperties()</code> 方法来执行刷新。</p><p><code>gs.PropertiesRefresher</code> 是 Go-Spring 注册到 IoC 容器里的内置 Bean，使用时直接注入即可。</p><p>看个例子：</p><div class="language-go vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">go</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">type</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> ConfigManager</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> struct</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">	Refresher </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">*</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">gs</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">PropertiesRefresher</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> `autowire:&quot;&quot;`</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">func</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">m </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">*</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ConfigManager</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ReloadConfig</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">() </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">error</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">	os.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Setenv</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;GS_SERVICE_TIMEOUT&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;10s&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">	return</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> m.Refresher.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">RefreshProperties</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">()</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>调用 <code>RefreshProperties()</code> 方法时，Go-Spring 会重新加载所有配置，并按优先级完成合并。接着，它会与旧配置进行 diff，找出发生变化的配置项，然后定位这些配置项对应的动态字段，最后把新值应用到动态字段上。</p><p><code>RefreshProperties()</code> 在执行时，会首先对所有差异项进行类型检查和 <code>expr</code> 表达式验证。只要有任何一个差异项验证失败，整个刷新过程就会终止。这样可以避免应用进入“部分字段已经更新、部分字段仍然是旧值”的混乱状态。</p><p>我们可以使用定时刷新、推送刷新等不同方式来触发刷新。由于频繁检查可能带来额外开销，因此在生产环境中，需要根据配置来源和业务场景设计合适的刷新策略。</p><h3 id="资源重建" tabindex="-1">资源重建 <a class="header-anchor" href="#资源重建" aria-label="Permalink to &quot;资源重建&quot;">​</a></h3><p>对于开关、阈值、超时时间这类轻量参数，我们通常不需要过多关心它们具体在什么时候被更新。但是，对于数据库连接池、Redis 客户端、消息队列连接、HTTP 客户端等拥有独立生命周期的对象，就需要额外关注资源的重建和回收。因为配置值刷新了，并不意味着已经创建出来的资源对象也会自动变化。</p><p>比如连接池的地址、用户名、密码、最大连接数发生变化后，旧连接池里可能还有正在执行的请求，直接关闭的话会影响线上流量。如果立刻切到新连接池，也可能因为连接复用被打断、短时间重新建连而带来额外抖动。因此，资源重建不应该简单理解为“配置一变就马上销毁旧对象、创建新对象”。</p><p>更稳妥的做法，是把资源生命周期交给专门的资源管理逻辑处理。它可以在创建资源时读取当前配置，然后在关键配置确实发生变化或资源超过失效时间后，再创建新资源，同时让旧资源继续服务已经进入的请求，等请求自然结束后再回收。这样的话，既不需要监听每一次配置变化，也能让资源切换更加平滑。</p><h2 id="go-spring-配置体系" tabindex="-1">Go-Spring 配置体系 <a class="header-anchor" href="#go-spring-配置体系" aria-label="Permalink to &quot;Go-Spring 配置体系&quot;">​</a></h2><p>到这里，我们已经完整介绍了 Go-Spring 配置体系。但一个完整的应用还需要回答更多的问题，比如对象应该由谁创建，依赖关系应该怎样组织，初始化和销毁逻辑应该放在哪里，多个组件之间又应该如何协作。因此，接下来开始介绍 Go-Spring 的 IoC 部分，看看 Go-Spring 是如何管理对象、装配依赖，并把这些配置真正作用到应用组件上的。</p>',32)])])}const g=i(n,[["render",h]]);export{E as __pageData,g as default};
